from profinet_scanner import extract_profinet_payload, parse_dcp_payload
from scapy.all import Ether

hexes = [
    '',
    '00000000000000193152185e810000018892feff050100010000000000760205001a000002010202020302040205010101020505050302070206ffff0102000e0001c0ae010cffffff00c0ae010c0202000d00006c61622d626e6930306b6a00020300060000037855400204000400000100020100160000424e49205847352d3533382d3042352d523036370207000400000001',
    '0000000000000019313e7027810000018892feff0501000100000000006a0202000d00006c61622d626e6930303568000102000e0001c0ae010affffff00c0ae010a0203000600000378508a0205000e000001020201020202030204020702040004000001000207000400000001020100160000424e4920504e542d3530382d3130352d5a303135',
]

for hex_str in hexes:
    pkt = Ether(bytes.fromhex(hex_str))
    src_mac, payload = extract_profinet_payload(pkt)
    result = parse_dcp_payload(src_mac, payload)
    print(f"MAC={result['mac']}  IP={result['ip']}  name={result['name_of_station']}  vendor={result['vendor_id']}  device={result['device_id']}")